# Gerado a partir de spark/sql/ (pasta sql removida; conteúdo embutido para paridade com dbt).

PIPELINE_SQL = 'WITH base AS (\n  SELECT * FROM glue_catalog.bronze.bronze_tasy_conta_paciente b\n  \n  WHERE b._bronze_loaded_at > (\n      SELECT COALESCE(MAX(s._silver_processed_at), CAST(\'1900-01-01\' AS TIMESTAMP))\n      FROM glue_catalog.silver.silver_tasy_conta_paciente s\n  )\n  \n)\n, latest_by_pk AS (\n  SELECT *\n  FROM (\n    SELECT\n        b.*\n      , ROW_NUMBER() OVER (\n          PARTITION BY b.nr_atendimento\n          ORDER BY\n              CAST(COALESCE(b._cdc_ts_ms, 0) AS BIGINT) DESC\n            , CAST(COALESCE(b.__source_txid, 0) AS BIGINT) DESC\n        ) AS _rn\n    FROM base b\n  ) x\n  WHERE _rn = 1\n)\n,\nshaped AS (\n  SELECT\n      d.nr_atendimento AS nr_atendimento\n    , CASE\n  WHEN d.dh_acerto_conta IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_acerto_conta AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_acerto_conta AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_acerto_conta AS TIMESTAMP)\nEND AS dh_acerto_conta\n    , LOWER(COALESCE(NULLIF(TRIM(CAST(d.ie_status_acerto AS STRING)), \'\'), \'i\')) AS ie_status_acerto\n    , CASE\n  WHEN d.dh_periodo_inicial IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_periodo_inicial AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_periodo_inicial AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_periodo_inicial AS TIMESTAMP)\nEND AS dh_periodo_inicial\n    , CASE\n  WHEN d.dh_periodo_final IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_periodo_final AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_periodo_final AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_periodo_final AS TIMESTAMP)\nEND AS dh_periodo_final\n    , CASE\n  WHEN d.dh_atualizacao IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_atualizacao AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_atualizacao AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_atualizacao AS TIMESTAMP)\nEND AS dh_atualizacao\n    , INITCAP(COALESCE(NULLIF(TRIM(CAST(d.nm_usuario AS STRING)), \'\'), \'indefinido\')) AS nm_usuario\n    , COALESCE(d.cd_convenio_parametro, CAST(-1 AS BIGINT)) AS cd_convenio_parametro\n    , COALESCE(d.nr_protocolo, CAST(-1 AS BIGINT)) AS nr_protocolo\n    , CASE\n  WHEN d.dh_mesano_referencia IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_mesano_referencia AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_mesano_referencia AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_mesano_referencia AS TIMESTAMP)\nEND AS dh_mesano_referencia\n    , CASE\n  WHEN d.dh_mesano_contabil IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_mesano_contabil AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_mesano_contabil AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_mesano_contabil AS TIMESTAMP)\nEND AS dh_mesano_contabil\n    , COALESCE(d.cd_convenio_calculo, CAST(-1 AS BIGINT)) AS cd_convenio_calculo\n    , COALESCE(d.cd_categoria_calculo, CAST(-1 AS BIGINT)) AS cd_categoria_calculo\n    , COALESCE(d.nr_interno_conta, CAST(-1 AS BIGINT)) AS nr_interno_conta\n    , COALESCE(d.nr_seq_protocolo, CAST(-1 AS BIGINT)) AS nr_seq_protocolo\n    , COALESCE(d.cd_categoria_parametro, CAST(-1 AS BIGINT)) AS cd_categoria_parametro\n    , INITCAP(COALESCE(NULLIF(TRIM(CAST(d.ds_inconsistencia AS STRING)), \'\'), \'indefinido\')) AS ds_inconsistencia\n    , CASE\n  WHEN d.dh_recalculo IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_recalculo AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_recalculo AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_recalculo AS TIMESTAMP)\nEND AS dh_recalculo\n    , COALESCE(d.cd_estabelecimento, CAST(-1 AS BIGINT)) AS cd_estabelecimento\n    , LOWER(COALESCE(NULLIF(TRIM(CAST(d.ie_cancelamento AS STRING)), \'\'), \'i\')) AS ie_cancelamento\n    , COALESCE(d.nr_lote_contabil, CAST(-1 AS BIGINT)) AS nr_lote_contabil\n    , COALESCE(d.nr_seq_apresent, CAST(-1 AS BIGINT)) AS nr_seq_apresent\n    , LOWER(COALESCE(NULLIF(TRIM(CAST(d.ie_complexidade AS STRING)), \'\'), \'i\')) AS ie_complexidade\n    , LOWER(COALESCE(NULLIF(TRIM(CAST(d.ie_tipo_guia AS STRING)), \'\'), \'i\')) AS ie_tipo_guia\n    , COALESCE(d.cd_autorizacao, CAST(-1 AS BIGINT)) AS cd_autorizacao\n    , COALESCE(\n  ROUND(CAST(d.vl_conta AS DECIMAL(38, 6)), 2),\n  CAST(-1.0 AS DECIMAL(38, 2))\n) AS vl_conta\n    , COALESCE(\n  ROUND(CAST(d.vl_desconto AS DECIMAL(38, 6)), 2),\n  CAST(-1.0 AS DECIMAL(38, 2))\n) AS vl_desconto\n    , COALESCE(d.nr_seq_conta_origem, CAST(-1 AS BIGINT)) AS nr_seq_conta_origem\n    , LOWER(COALESCE(NULLIF(TRIM(CAST(d.ie_tipo_nascimento AS STRING)), \'\'), \'i\')) AS ie_tipo_nascimento\n    , CASE\n  WHEN d.dh_cancelamento IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_cancelamento AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_cancelamento AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_cancelamento AS TIMESTAMP)\nEND AS dh_cancelamento\n    , COALESCE(d.cd_proc_princ, CAST(-1 AS BIGINT)) AS cd_proc_princ\n    , COALESCE(d.nr_conta_convenio, CAST(-1 AS BIGINT)) AS nr_conta_convenio\n    , CASE\n  WHEN d.dh_conta_definitiva IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_conta_definitiva AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_conta_definitiva AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_conta_definitiva AS TIMESTAMP)\nEND AS dh_conta_definitiva\n    , CASE\n  WHEN d.dh_conta_protocolo IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_conta_protocolo AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_conta_protocolo AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_conta_protocolo AS TIMESTAMP)\nEND AS dh_conta_protocolo\n    , COALESCE(d.nr_seq_conta_prot, CAST(-1 AS BIGINT)) AS nr_seq_conta_prot\n    , COALESCE(d.nr_seq_pq_protocolo, CAST(-1 AS BIGINT)) AS nr_seq_pq_protocolo\n    , INITCAP(COALESCE(NULLIF(TRIM(CAST(d.ds_observacao AS STRING)), \'\'), \'indefinido\')) AS ds_observacao\n    , LOWER(COALESCE(NULLIF(TRIM(CAST(d.ie_tipo_atend_tiss AS STRING)), \'\'), \'i\')) AS ie_tipo_atend_tiss\n    , COALESCE(d.nr_seq_saida_consulta, CAST(-1 AS BIGINT)) AS nr_seq_saida_consulta\n    , COALESCE(d.nr_seq_saida_int, CAST(-1 AS BIGINT)) AS nr_seq_saida_int\n    , COALESCE(d.nr_seq_saida_spsadt, CAST(-1 AS BIGINT)) AS nr_seq_saida_spsadt\n    , CASE\n  WHEN d.dh_geracao_tiss IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_geracao_tiss AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_geracao_tiss AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_geracao_tiss AS TIMESTAMP)\nEND AS dh_geracao_tiss\n    , COALESCE(d.nr_lote_repasse, CAST(-1 AS BIGINT)) AS nr_lote_repasse\n    , LOWER(COALESCE(NULLIF(TRIM(CAST(d.ie_reapresentacao_sus AS STRING)), \'\'), \'i\')) AS ie_reapresentacao_sus\n    , COALESCE(d.nr_seq_ret_glosa, CAST(-1 AS BIGINT)) AS nr_seq_ret_glosa\n    , CASE\n  WHEN d.dh_prev_protocolo IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_prev_protocolo AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_prev_protocolo AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_prev_protocolo AS TIMESTAMP)\nEND AS dh_prev_protocolo\n    , COALESCE(d.nr_conta_pacote_exced, CAST(-1 AS BIGINT)) AS nr_conta_pacote_exced\n    , CASE\n  WHEN d.dh_alta_tiss IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_alta_tiss AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_alta_tiss AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_alta_tiss AS TIMESTAMP)\nEND AS dh_alta_tiss\n    , CASE\n  WHEN d.dh_entrada_tiss IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_entrada_tiss AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_entrada_tiss AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_entrada_tiss AS TIMESTAMP)\nEND AS dh_entrada_tiss\n    , LOWER(COALESCE(NULLIF(TRIM(CAST(d.ie_tipo_fatur_tiss AS STRING)), \'\'), \'i\')) AS ie_tipo_fatur_tiss\n    , LOWER(COALESCE(NULLIF(TRIM(CAST(d.ie_tipo_consulta_tiss AS STRING)), \'\'), \'i\')) AS ie_tipo_consulta_tiss\n    , COALESCE(d.cd_especialidade_conta, CAST(-1 AS BIGINT)) AS cd_especialidade_conta\n    , COALESCE(d.cd_plano_retorno_conv, CAST(-1 AS BIGINT)) AS cd_plano_retorno_conv\n    , LOWER(COALESCE(NULLIF(TRIM(CAST(d.ie_tipo_atend_conta AS STRING)), \'\'), \'i\')) AS ie_tipo_atend_conta\n    , COALESCE(\n  ROUND(CAST(d.qt_dias_conta AS DECIMAL(38, 6)), 2),\n  CAST(-1.0 AS DECIMAL(38, 2))\n) AS qt_dias_conta\n    , COALESCE(d.cd_responsavel, CAST(-1 AS BIGINT)) AS cd_responsavel\n    , COALESCE(d.nr_seq_estagio_conta, CAST(-1 AS BIGINT)) AS nr_seq_estagio_conta\n    , INITCAP(COALESCE(NULLIF(TRIM(CAST(d.nm_usuario_original AS STRING)), \'\'), \'indefinido\')) AS nm_usuario_original\n    , COALESCE(d.nr_seq_audit_hist_glosa, CAST(-1 AS BIGINT)) AS nr_seq_audit_hist_glosa\n    , COALESCE(\n  ROUND(CAST(d.vl_repasse_conta AS DECIMAL(38, 6)), 2),\n  CAST(-1.0 AS DECIMAL(38, 2))\n) AS vl_repasse_conta\n    , COALESCE(d.nr_fechamento, CAST(-1 AS BIGINT)) AS nr_fechamento\n    , COALESCE(d.nr_seq_tipo_fatura, CAST(-1 AS BIGINT)) AS nr_seq_tipo_fatura\n    , COALESCE(d.nr_seq_apresentacao, CAST(-1 AS BIGINT)) AS nr_seq_apresentacao\n    , COALESCE(d.nr_seq_motivo_cancel, CAST(-1 AS BIGINT)) AS nr_seq_motivo_cancel\n    , CASE\n  WHEN d.dh_conferencia_sus IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_conferencia_sus AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_conferencia_sus AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_conferencia_sus AS TIMESTAMP)\nEND AS dh_conferencia_sus\n    , COALESCE(d.cd_medico_conta, CAST(-1 AS BIGINT)) AS cd_medico_conta\n    , COALESCE(\n  ROUND(CAST(d.qt_dias_periodo AS DECIMAL(38, 6)), 2),\n  CAST(-1.0 AS DECIMAL(38, 2))\n) AS qt_dias_periodo\n    , CASE\n  WHEN d.dh_geracao_resumo IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_geracao_resumo AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_geracao_resumo AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_geracao_resumo AS TIMESTAMP)\nEND AS dh_geracao_resumo\n    , COALESCE(\n  ROUND(CAST(d.vl_conta_relat AS DECIMAL(38, 6)), 2),\n  CAST(-1.0 AS DECIMAL(38, 2))\n) AS vl_conta_relat\n    , LOWER(COALESCE(NULLIF(TRIM(CAST(d.ie_faec AS STRING)), \'\'), \'i\')) AS ie_faec\n    , COALESCE(d.nr_seq_apresent_sus, CAST(-1 AS BIGINT)) AS nr_seq_apresent_sus\n    , COALESCE(d.nr_seq_status_fat, CAST(-1 AS BIGINT)) AS nr_seq_status_fat\n    , COALESCE(d.nr_seq_status_mob, CAST(-1 AS BIGINT)) AS nr_seq_status_mob\n    , COALESCE(d.nr_seq_regra_fluxo, CAST(-1 AS BIGINT)) AS nr_seq_regra_fluxo\n    , COALESCE(d.nr_conta_orig_desdob, CAST(-1 AS BIGINT)) AS nr_conta_orig_desdob\n    , CASE\n  WHEN d.dh_atual_conta_conv IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_atual_conta_conv AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_atual_conta_conv AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_atual_conta_conv AS TIMESTAMP)\nEND AS dh_atual_conta_conv\n    , COALESCE(\n  ROUND(CAST(d.pr_coseguro_hosp AS DECIMAL(38, 6)), 2),\n  CAST(-1.0 AS DECIMAL(38, 2))\n) AS pr_coseguro_hosp\n    , COALESCE(\n  ROUND(CAST(d.pr_coseguro_honor AS DECIMAL(38, 6)), 2),\n  CAST(-1.0 AS DECIMAL(38, 2))\n) AS pr_coseguro_honor\n    , COALESCE(\n  ROUND(CAST(d.vl_deduzido AS DECIMAL(38, 6)), 2),\n  CAST(-1.0 AS DECIMAL(38, 2))\n) AS vl_deduzido\n    , COALESCE(\n  ROUND(CAST(d.vl_base_conta AS DECIMAL(38, 6)), 2),\n  CAST(-1.0 AS DECIMAL(38, 2))\n) AS vl_base_conta\n    , CASE\n  WHEN d.dh_definicao_conta IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_definicao_conta AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_definicao_conta AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_definicao_conta AS TIMESTAMP)\nEND AS dh_definicao_conta\n    , COALESCE(d.nr_seq_ordem, CAST(-1 AS BIGINT)) AS nr_seq_ordem\n    , LOWER(COALESCE(NULLIF(TRIM(CAST(d.ie_complex_aih_orig AS STRING)), \'\'), \'i\')) AS ie_complex_aih_orig\n    , COALESCE(\n  ROUND(CAST(d.vl_coseguro_honor AS DECIMAL(38, 6)), 2),\n  CAST(-1.0 AS DECIMAL(38, 2))\n) AS vl_coseguro_honor\n    , COALESCE(d.nr_seq_tipo_cobranca, CAST(-1 AS BIGINT)) AS nr_seq_tipo_cobranca\n    , COALESCE(\n  ROUND(CAST(d.vl_coseguro_hosp AS DECIMAL(38, 6)), 2),\n  CAST(-1.0 AS DECIMAL(38, 2))\n) AS vl_coseguro_hosp\n    , COALESCE(\n  ROUND(CAST(d.pr_coseg_nivel_hosp AS DECIMAL(38, 6)), 2),\n  CAST(-1.0 AS DECIMAL(38, 2))\n) AS pr_coseg_nivel_hosp\n    , COALESCE(\n  ROUND(CAST(d.vl_coseg_nivel_hosp AS DECIMAL(38, 6)), 2),\n  CAST(-1.0 AS DECIMAL(38, 2))\n) AS vl_coseg_nivel_hosp\n    , COALESCE(\n  ROUND(CAST(d.vl_maximo_coseguro AS DECIMAL(38, 6)), 2),\n  CAST(-1.0 AS DECIMAL(38, 2))\n) AS vl_maximo_coseguro\n    , LOWER(COALESCE(NULLIF(TRIM(CAST(d.ie_claim_type AS STRING)), \'\'), \'i\')) AS ie_claim_type\n    , COALESCE(d.nr_codigo_controle, CAST(-1 AS BIGINT)) AS nr_codigo_controle\n    , COALESCE(d.nr_seq_categoria_iva, CAST(-1 AS BIGINT)) AS nr_seq_categoria_iva\n    , CASE\n  WHEN d.dh_geracao_rel_conv IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_geracao_rel_conv AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_geracao_rel_conv AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_geracao_rel_conv AS TIMESTAMP)\nEND AS dh_geracao_rel_conv\n    , COALESCE(d.nr_conta_lei_prov, CAST(-1 AS BIGINT)) AS nr_conta_lei_prov\n    , LOWER(COALESCE(NULLIF(TRIM(CAST(d.ie_integration AS STRING)), \'\'), \'i\')) AS ie_integration\n    , COALESCE(d.nr_guia_prestador, CAST(-1 AS BIGINT)) AS nr_guia_prestador\n    , COALESCE(NULLIF(TRIM(CAST(d.id_delivery AS STRING)), \'\'), "\'ind\'") AS id_delivery\n    , LOWER(COALESCE(NULLIF(TRIM(CAST(d.ie_consist_prot AS STRING)), \'\'), \'i\')) AS ie_consist_prot\n    , LOWER(COALESCE(NULLIF(TRIM(CAST(d.ie_status AS STRING)), \'\'), \'i\')) AS ie_status\n    , COALESCE(d.cd_plano, CAST(-1 AS BIGINT)) AS cd_plano\n    , CASE\n  WHEN d.dh_geracao_anexos_tiss IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_geracao_anexos_tiss AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_geracao_anexos_tiss AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_geracao_anexos_tiss AS TIMESTAMP)\nEND AS dh_geracao_anexos_tiss\n    , CASE\n  WHEN d.dh_fim_ger_doc_tiss_relats IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_fim_ger_doc_tiss_relats AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_fim_ger_doc_tiss_relats AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_fim_ger_doc_tiss_relats AS TIMESTAMP)\nEND AS dh_fim_ger_doc_tiss_relats\n    , CASE\n  WHEN d.dh_fim_ger_doc_tiss_laudos IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_fim_ger_doc_tiss_laudos AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_fim_ger_doc_tiss_laudos AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_fim_ger_doc_tiss_laudos AS TIMESTAMP)\nEND AS dh_fim_ger_doc_tiss_laudos\n    , CASE\n  WHEN d.dh_fim_ger_doc_tiss_exames IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_fim_ger_doc_tiss_exames AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_fim_ger_doc_tiss_exames AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_fim_ger_doc_tiss_exames AS TIMESTAMP)\nEND AS dh_fim_ger_doc_tiss_exames\n    \n    , d._is_deleted AS _is_deleted\n    , d._cdc_op AS _cdc_op\n    , d._cdc_event_at AS _cdc_event_at\n    , d._cdc_ts_ms AS _cdc_ts_ms\n    , d._row_hash AS _bronze_row_hash\n    , d._bronze_loaded_at AS _bronze_loaded_at\n    , from_utc_timestamp(current_timestamp(), \'America/Sao_Paulo\') AS _silver_processed_at\n    , CAST(uuid() AS STRING) AS _dbt_invocation_id\n  FROM latest_by_pk d\n)\n, final AS (\n  SELECT *\n  FROM shaped\n  WHERE NOT _is_deleted\n)\nSELECT * FROM final\n'
